const memories = $('Get Memories').all();
const conversations = $('Get Conversations').all();

// Group memories by type
const grouped = {};
for (const item of memories) {
  const { type, name, description, content } = item.json;
  if (!grouped[type]) grouped[type] = [];
  grouped[type].push(`### ${name}\n${description ? description + '\n' : ''}${content}`);
}

// Build memories section
let output = '## Active Memories\n\n';
for (const [type, entries] of Object.entries(grouped)) {
  output += `**${type.toUpperCase()}**\n\n`;
  output += entries.join('\n\n') + '\n\n';
}

// Build conversations section
output += '## Recent Sessions\n\n';
if (conversations.length === 0) {
  output += 'No previous sessions recorded.\n';
} else {
  for (const item of conversations) {
    const { session_date, persona, topics, summary, key_decisions } = item.json;
    const date = new Date(session_date).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    output += `**${date}${persona ? ' — ' + persona : ''}**\n`;
    output += `${summary}\n`;
    if (key_decisions) output += `Decisions: ${key_decisions}\n`;
    output += '\n';
  }
}

return [{ json: { context: output } }];

